// Generated by OrchestKit Claude Plugin

// Guards the orank "Web Bot Auth directory" recovery: the
// /.well-known/http-message-signatures-directory must serve a spec-shaped
// Ed25519 key directory (RFC 9421) and be allowlisted so agents get it, not a
// 404. Pure handler invocation — no server, no network.

import { describe, expect, it } from "vitest";
import { GET } from "@/app/api/well-known/http-message-signatures-directory/route";
import { isServedPath } from "@/lib/agent-404";

describe("Web Bot Auth key directory", () => {
	it("serves a keys[] array of Ed25519 JWKs with nbf/exp", async () => {
		const res = GET();
		expect(res.headers.get("Content-Type")).toContain("json");
		const body = (await res.json()) as {
			keys: Array<Record<string, unknown>>;
		};
		expect(Array.isArray(body.keys)).toBe(true);
		expect(body.keys.length).toBeGreaterThan(0);
		const jwk = body.keys[0];
		expect(jwk.kty).toBe("OKP");
		expect(jwk.crv).toBe("Ed25519");
		expect(jwk.alg).toBe("EdDSA");
		expect(jwk.use).toBe("sig");
		expect(typeof jwk.x).toBe("string");
		expect((jwk.x as string).length).toBeGreaterThan(0);
		expect(typeof jwk.kid).toBe("string");
		expect(typeof jwk.nbf).toBe("number");
		expect(typeof jwk.exp).toBe("number");
		expect(jwk.exp as number).toBeGreaterThan(jwk.nbf as number);
	});

	it("is allowlisted so agents receive it (not a JSON 404)", () => {
		expect(
			isServedPath("/.well-known/http-message-signatures-directory"),
		).toBe(true);
	});
});
